// Difficulty tiers
// easy      → low friction, builds momentum
// hard      → requires real effort and discomfort
// legendary → rare, brutal, identity-level challenges

export type Difficulty = 'easy' | 'hard' | 'legendary'

export type TaskItem = {
  id: string
  category: string
  label: string
  penalty: string        // what you lose by skipping
  xp: number
  difficulty: Difficulty
}

export type RawTask = {
  label: string
  penalty: string
  xp: number
  difficulty: Difficulty
}

